    # A < B if S_A S_B < S_B S_A (i.e., we want B to come before A if S_A S_B < S_B S_A)
    # We want A to precede B if S_A S_B > S_B S_A.

    blocks.sort(&) { |a, b|
        // Returns true if 'a' should come before 'b'
        // Equivalent to should_precede(a.p, a.z, b.p, b.z)

        if a.p > b.p {
            true // S_A S_B > S_B S_A
        } else if b.p > a.p {
            false // S_A S_B < S_B S_A
        } else { // a.p == b.p
            // Compare z_a vs z_b
            if a.z < b.z {
                true // S_A S_B > S_B S_A (because smaller Z means less trailing zeros in the first part of the comparison)
            } else if b.z < a.z {
                false
            } else { // a.z == b.z
                false // Equal, relative order doesn't matter
            }
        }
    }

    # 3. Calculate the total value in modular arithmetic

    total_value: Int64 = 0
    remaining_length: Int64 = 0

    // Process blocks in sorted order (from left to right)
    for block in blocks
        // When block_k is placed, it contributes its intrinsic value multiplied by 2^(total length of blocks to its right)
        // The length of blocks to the right is the sum of L_j for all j > k.

        // Instead of calculating the total length to the right, we can calculate the contribution
        // of block_k based on the total length of all blocks $L_{total}$, and the length of blocks before it, $L_{prefix}$.

        // Let $L_{total} = \sum L_i$.
        // If $S_k$ is at position $k$ (0-indexed), it is followed by $N-1-k$ blocks.
        // Let $L_{suffix}(k) = \sum_{j=k+1}^{N-1} L_j$.
        // Contribution = $(2^{L_k} - 2^{Z_k}) \cdot 2^{L_{suffix}(k)} \pmod M$.

        // We calculate $L_{total}$ first.
        remaining_length += block.l // remaining_length now accumulates $L_{total}$ if we iterate backwards, but we are iterating forwards.
    end

    // Reset and recalculate L_total
    l_total: Int64 = 0
    for block in blocks
        l_total = (l_total + block.l) % MOD // Modulo is not strictly needed for L_total here, but helpful for power calculation if we were to use it.
    end

    // Now, iterate forwards and keep track of the length already placed (prefix length)
    prefix_length: Int64 = 0
    total_value = 0

    for block in blocks
        p = block.p
        z = block.z
        l = block.l

        // Length of blocks to the right: $L_{suffix} = L_{total} - (\text{prefix\_length} + L)$
        l_suffix: Int64 = (l_total - (prefix_length + l) % MOD + MOD) % MOD

        // Intrinsic value of block: $V_k = 2^L - 2^Z \pmod M$
        // Modular exponentiation: pow(base, exponent, modulus)

        // $2^L \pmod M$
        pow_2_l = power(2, l, MOD)

        // $2^Z \pmod M$
        pow_2_z = power(2, z, MOD)

        // $V_k = (2^L - 2^Z) \pmod M$
        v_k = (pow_2_l - pow_2_z + MOD) % MOD

        // Contribution: $V_k \cdot 2^{L_{suffix}} \pmod M$
        contribution = (v_k * power(2, l_suffix, MOD)) % MOD

        // Accumulate total value
        total_value = (total_value + contribution) % MOD

        // Update prefix length
        prefix_length = (prefix_length + l) % MOD
    end

    return total_value
end

# Modular exponentiation helper
def power(base: Int64, exp: Int64, mod: Int64): Int64
    res: Int64 = 1
    base = base % mod
    while exp > 0
        if exp % 2 == 1
            res = (res * base) % mod
        end
        base = (base * base) % mod
        exp /= 2
    end
    res
